class Solution:
    def findEvenNumbers(self, digits: List[int]) -> List[int]:
        cnt = [0] * 10
        for d in digits:
            cnt[d] += 1

        ans = []
        append = ans.append

        for h in range(1, 10):
            if cnt[h]:
                cnt[h] -= 1
                for t in range(10):
                    if cnt[t]:
                        cnt[t] -= 1
                        base = h * 100 + t * 10
                        for u in (0, 2, 4, 6, 8):
                            if cnt[u]:
                                append(base + u)
                        cnt[t] += 1
                cnt[h] += 1

        return ans
```

